// // This module decodes 4-bit inputs into 16-bit outputs, but only activates the least significant bit for each input.
module decoder4to16 (
    input [3:0] in,
    output reg [15:0] out
);
    always @(*) begin
        out = 16'b0; // Clear all outputs
        out[in] = 1'b1; // Activate the output corresponding to the input
    end
endmodule
